        toolbar: {
          show: false,
        },
      },
      dataLabels: {
        enabled: false,
      },
      colors: [colors[0]],
      title: {
        text: "HeatMap Chart (Single color)",
        style: {
          fontWeight: 500,
        },
      },
      stroke: {
        colors: [colors[1]]
    }
    };
  }

